// Design Ref: §4.7 — RSS JSON에서 기사 객체 추출
const data = $input.first().json;
const keyword = $('Loop Over Keywords').first().json.keyword;
const channel = $('Loop Over Keywords').first().json.channel;

// XML 파싱 결과에서 items 추출
let items = [];
try {
  const rss = data?.rss || data?.data?.rss;
  if (rss?.channel?.item) {
    items = Array.isArray(rss.channel.item) ? rss.channel.item : [rss.channel.item];
  }
} catch (e) {
  // XML 파싱 실패 시 빈 배열 반환
  return [];
}

const articles = items.map(item => ({
  keyword,
  channel,
  title: (item.title || item.title?._text || '').toString(),
  link: (item.link || item.link?._text || '').toString(),
  pubDate: (item.pubDate || item.pubDate?._text || '').toString(),
  source: (item.source?._text || item.source?._ || item.source || '').toString()
}));

return articles.filter(a => a.title && a.link).map(a => ({ json: a }));

// Design Ref: §4.9 — 최근 24시간 내 발행 기사만 유지
// Plan SC: SC-1 (기존 Apps Script와 동일한 수집 품질)
const now = new Date();
const oneDayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const filtered = $input.all().filter(item => {
  try {
    const pubDate = new Date(item.json.pubDate);
    return pubDate >= oneDayAgo && !isNaN(pubDate.getTime());
  } catch (e) {
    return false;
  }
});

return filtered;

