return $input.all().filter(item => {
  const title = item.json.title;

  // "할인" 제외
  if (title.includes("할인")) return false;

  // 야구 키워드 제외
  const lowerTitle = title.toLowerCase();
  const hasBaseball = baseballExcludeKeywords.some(
    word => lowerTitle.includes(word.toLowerCase())
  );
  if (hasBaseball) return false;

  // SSG 선수명 제외
  const hasPlayer = ssgPlayerNames.some(name => title.includes(name));
  if (hasPlayer) return false;

  return true;
});

// Design Ref: §4.11 — Levenshtein 유사도 기반 중복 제거
// Plan SC: SC-1 (기존 Apps Script와 동일한 중복 제거)
function getLevenshteinSimilarity(str1, str2) {
  const len1 = str1.length;
  const len2 = str2.length;

  if (len1 === 0) return 0;
  if (len2 === 0) return 0;

  const dp = Array(len1 + 1).fill(null).map(() => Array(len2 + 1).fill(0));

  for (let i = 0; i <= len1; i++) dp[i][0] = i;
  for (let j = 0; j <= len2; j++) dp[0][j] = j;

  for (let i = 1; i <= len1; i++) {
    for (let j = 1; j <= len2; j++) {
      const cost = str1[i-1] === str2[j-1] ? 0 : 1;
      dp[i][j] = Math.min(dp[i-1][j]+1, dp[i][j-1]+1, dp[i-1][j-1]+cost);
    }
  }

  const distance = dp[len1][len2];
  return (Math.max(len1, len2) - distance) / Math.max(len1, len2);
}

const processed = [];
const results = [];

for (const item of $input.all()) {
  // 제목에서 언론사 정보 제거
  const title = item.json.title.replace(/ - [^-]+$/, "");

  const isSimilar = processed.some(
    prev => getLevenshteinSimilarity(prev, title) > 0.2
  );

  if (!isSimilar) {
    processed.push(title);
    results.push({ json: { ...item.json, title } });
  }
}

return results;

// Design Ref: §4.12 — 기사 유형 자동 분류
// Plan SC: SC-1 (기존 Apps Script와 동일한 분류)
return $input.all().map(item => {
  const title = item.json.title;
  let type = "일반 뉴스";

  if (title.includes("출시") || title.includes("신제품")) type = "신제품 출시";
  else if (title.includes("확대") || title.includes("점포") || title.includes("매장")) type = "사업 확장";
  else if (title.includes("배송") || title.includes("물류") || title.includes("운송")) type = "물류/배송 관련";
  else if (title.includes("투자") || title.includes("자금") || title.includes("매출")) type = "투자/매출 관련";
  else if (title.includes("채용") || title.includes("인재") || title.includes("고용")) type = "인재 채용";
  else if (title.includes("협업") || title.includes("파트너십") || title.includes("제휴")) type = "협업/제휴";
  else if (title.includes("고객") || title.includes("이용자")) type = "고객 관련";

  return { json: { ...item.json, type } };
});

// Design Ref: §4.14 — Google Sheets 저장을 위한 데이터 준비
// AI 요약 결과와 기사 목록을 함께 전달
const aiSummary = $('AI Summary').first()?.json?.message?.content || '요약 생성 실패';
const articles = $('Type Classifier').all();

// 기사 데이터를 Sheets 형식으로 변환
return articles.map((item, idx) => ({
  json: {
    ...item.json,
    aiSummary,
    articleIndex: idx + 1,
    formattedDate: new Date(item.json.pubDate).toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' })
  }
}));

// Design Ref: §4.16 — Slack 메시지 포맷팅
const articles = $input.all();
const aiSummary = articles[0]?.json?.aiSummary || '요약 없음';

const onlineArticles = articles
  .filter(i => i.json.channel === '온라인')
  .slice(0, 5)
  .map(i => `• <${i.json.link}|${i.json.title}> (${i.json.keyword})`)
  .join('\n');

const offlineArticles = articles
  .filter(i => i.json.channel === '오프라인')
  .slice(0, 5)
  .map(i => `• <${i.json.link}|${i.json.title}> (${i.json.keyword})`)
  .join('\n');

const today = new Date().toLocaleDateString('ko-KR', { timeZone: 'Asia/Seoul' });

const message = `📰 *쇼핑 플랫폼 뉴스 브리핑* (${today})\n\n*🤖 AI 요약:*\n${aiSummary}\n\n━━━━━━━━━━━━━━━━━━━━━\n\n*📋 주요 기사 (총 ${articles.length}건)*\n\n*[온라인]*\n${onlineArticles || '• 해당 없음'}\n\n*[오프라인]*\n${offlineArticles || '• 해당 없음'}`;

return [{ json: { message, totalCount: articles.length } }];

// Design Ref: §4.17 — HTML 이메일 본문 생성
// Plan SC: SC-3 (이메일 발송, 기존 형식 유지)
const articles = $input.all();
const aiSummary = articles[0]?.json?.aiSummary || '요약 생성 실패';
const now = new Date().toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' });

function escapeHtml(text) {
  return String(text)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

let rows = '';
articles.forEach((item, idx) => {
  const a = item.json;
  rows += `<tr>
    <td style="text-align:center;">${idx + 1}</td>
    <td style="text-align:center;">${a.channel}</td>
    <td style="text-align:center;">${a.keyword}</td>
    <td style="text-align:center;">${a.type}</td>
    <td style="text-align:left;"><a href="${a.link}" target="_blank">${escapeHtml(a.title)}</a></td>
    <td style="text-align:center;">${a.formattedDate}</td>
  </tr>`;
});

const htmlBody = `
<h2>쇼핑 플랫폼 뉴스 (최근 하루 내 발행분)</h2>
<p><strong>🤖 AI 요약:</strong></p>
<p style="background-color:#f8f9fa;padding:12px;border-radius:6px;">${aiSummary.replace(/\n/g, '<br>')}</p>
<hr>
<table border="1" cellspacing="0" cellpadding="8" style="border-collapse:collapse;width:100%;font-size:13px;">
  <thead style="background-color:#f2f2f2;">
    <tr>
      <th style="text-align:center;">#</th>
      <th style="text-align:center;">채널</th>
      <th style="text-align:center;">키워드</th>
      <th style="text-align:center;">유형</th>
      <th style="text-align:center;">제목</th>
      <th style="text-align:center;">발행일</th>
    </tr>
  </thead>
  <tbody>
    ${rows}
  </tbody>
</table>
<p style="color:#666;font-size:11px;">자동 생성: n8n News Scraper | ${now}</p>
`;

return [{ json: { htmlBody, subject: `쇼핑 플랫폼 뉴스 (최근 하루) - ${now}`, totalCount: articles.length } }];
